def perceive(data):
    if isinstance(data, dict):
        text = str(data.get("text", ""))
        rejected = data.get("rejected_claims")
    else:
        text = str(data)
        rejected = None
    if rejected is None:
        # Count claim references like "claim 1", "claim 12" in the OA body.
        words = text.replace(",", " ").replace(".", " ").split()
        rejected = 0
        for i, w in enumerate(words[:-1]):
            if w.lower() == "claim" and words[i + 1].isdigit():
                rejected += 1
    rejected = max(0, int(rejected))
    return {"pending_office_action": True, "rejected_claims": rejected}
